def pointwise_to_pairwise(
    scores_a: list[float],
    scores_b: list[float],
    tie_threshold: float = 0.5,
) -> dict:
    """
    Convert per-prompt pointwise scores to pairwise win/tie/loss counts.
    tie_threshold: margin below which a difference is called a tie.
    """
    results = {'win': 0, 'tie': 0, 'loss': 0}
    for a, b in zip(scores_a, scores_b):
        diff = a - b
        if diff > tie_threshold:
            results['win'] += 1
    elif diff < -tie_threshold:
            results['loss'] += 1
    else:
            results['tie'] += 1
    total = len(scores_a)
    win_rate = (results['win'] + 0.5 * results['tie']) / total
    return {**results, 'win_rate': win_rate}

# Example
a_scores = [4, 5, 3, 4, 2]
b_scores = [3, 4, 4, 2, 3]
print(pointwise_to_pairwise(a_scores, b_scores))
# {'win': 2, 'tie': 2, 'loss': 1, 'win_rate': 0.6}

from collections import defaultdict
import math

class EloRater:
    def __init__(self, k: float = 32, init_elo: float = 1200):
        self.k = k
        self.init_elo = init_elo
        self.elos = defaultdict(lambda: init_elo)
        self.battle_count = defaultdict(int)

    def expected(self, elo_a: float, elo_b: float) -> float:
        return 1 / (1 + 10 ** ((elo_b - elo_a) / 400))

    def update(self, model_a: str, model_b: str, outcome: float) -> None:
        # outcome: 1=A wins, 0=B wins, 0.5=tie
        ea = self.expected(self.elos[model_a], self.elos[model_b])
        eb = 1 - ea
        self.elos[model_a] += self.k * (outcome - ea)
        self.elos[model_b] += self.k * ((1 - outcome) - eb)
        self.battle_count[model_a] += 1
        self.battle_count[model_b] += 1

    def leaderboard(self) -> list[tuple[str, float, int]]:
        return sorted(
            [(m, round(e, 1), self.battle_count[m]) for m, e in self.elos.items()],
            key=lambda x: -x[1],
        )

# Usage
rater = EloRater()
battles = [('gpt-4o', 'gpt-3.5', 1.0), ('claude-3-5', 'gpt-4o', 0.5),
           ('gpt-4o', 'llama-3', 1.0), ('claude-3-5', 'llama-3', 1.0)]
for a, b, outcome in battles:
    rater.update(a, b, outcome)
for model, elo, n in rater.leaderboard():
    print(f'{model}: {elo}  ({n} battles)')
